final:
module RefModule (
    input [4:0] investment1,
    input [4:0] investment2,
    input [4:0] investment3,
    output [4:0] optimal_investment
);

  wire temp1_investment1 & investment2 = investment1 & investment2;
  wire temp2_investment3 = investment3;
  assign optimal_investment = temp1_investment1 & investment2 & temp2_investment3;

endmodule
